/* global console, process */
/*
 * two-witness-bench.mjs — plurality witnessed by two independent instruments.
 *
 * The Buley Test (Gnosis/BuleyTest.lean) demands an EXTERNAL witness; TwoBeingsNotOne
 * says a beat between clocks proves two beings. This drives both on the bench with
 * THREE oscillators: one Pluto TX + two NESDR RTL RX. TX a single tone; capture on
 * BOTH RTLs at once; measure each RTL's carrier offset (its beat against the Pluto)
 * and infer the beat between the two RTLs. Three pairwise beats => three distinct
 * beings — plurality witnessed by two eyes that do not share a clock. If a pair's
 * beat were ~0 they would be one being (a shared/locked clock). Run with /opt/homebrew/bin/node.
 */
import { spawn } from 'node:child_process';
import { openSync, readFileSync, writeFileSync, existsSync } from 'node:fs';

const FS = 2_400_000, LO = 433_920_000, N_TX = 131072, N_CAP = 2_400_000, N_FFT = 131072;
const CAP_SKIP = 400_000, DC_GUARD_HZ = 12_000, F0 = 300_000, SCALE = 8000;
const LIBIIO = process.env.GNOSIS_LIBIIO_BUILD || '/tmp/libiio_build/build';
const env = { ...process.env, DYLD_FALLBACK_FRAMEWORK_PATH: LIBIIO };
const IIO_ATTR = `${LIBIIO}/tests/iio_attr`, IIO_WRITEDEV = `${LIBIIO}/tests/iio_writedev`, IIO_INFO = `${LIBIIO}/tests/iio_info`;
const RTL = existsSync('/opt/homebrew/bin/rtl_sdr') ? '/opt/homebrew/bin/rtl_sdr' : 'rtl_sdr';
import { mkdirSync } from 'node:fs';
const ART = new URL('.', import.meta.url).pathname + '../.qa-artifacts/two-witness';
mkdirSync(ART, { recursive: true });

const sh = (cmd, args, opts = {}) => new Promise((res) => {
  const c = spawn(cmd, args, { env, ...opts });
  let o = '', e = ''; if (c.stdout) c.stdout.on('data', (d) => (o += d)); if (c.stderr) c.stderr.on('data', (d) => (e += d));
  c.once('close', (code) => res({ code, out: o, err: e }));
});

function fft(re, im) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) { let bit = n >> 1; for (; j & bit; bit >>= 1) j ^= bit; j ^= bit; if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; } }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = (-2 * Math.PI) / len, wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) { let cr = 1, ci = 0;
      for (let k = 0; k < len >> 1; k++) {
        const ar = re[i + k], ai = im[i + k];
        const br = re[i + k + (len >> 1)] * cr - im[i + k + (len >> 1)] * ci;
        const bi = re[i + k + (len >> 1)] * ci + im[i + k + (len >> 1)] * cr;
        re[i + k] = ar + br; im[i + k] = ai + bi; re[i + k + (len >> 1)] = ar - br; im[i + k + (len >> 1)] = ai - bi;
        const ncr = cr * wr - ci * wi; ci = cr * wi + ci * wr; cr = ncr;
      }
    }
  }
}

function synthTone(fHz) {
  const buf = Buffer.alloc(N_TX * 4);
  for (let n = 0; n < N_TX; n++) {
    const ph = (2 * Math.PI * fHz * n) / FS;
    buf.writeInt16LE(Math.round(Math.cos(ph) * SCALE), n * 4);
    buf.writeInt16LE(Math.round(Math.sin(ph) * SCALE), n * 4 + 2);
  }
  return buf;
}

function measureCarrier(u8) {
  const re = new Float64Array(N_FFT), im = new Float64Array(N_FFT);
  for (let k = 0; k < N_FFT; k++) { re[k] = u8[(CAP_SKIP + k) * 2] - 127.5; im[k] = u8[(CAP_SKIP + k) * 2 + 1] - 127.5; }
  fft(re, im);
  const binHz = FS / N_FFT, guard = Math.round(DC_GUARD_HZ / binHz);
  let peak = -1, peakMag = 0;
  for (let k = 0; k < N_FFT; k++) {
    const sb = k < N_FFT / 2 ? k : k - N_FFT;
    if (Math.abs(sb) <= guard) continue;
    const m = re[k] * re[k] + im[k] * im[k];
    if (m > peakMag) { peakMag = m; peak = k; }
  }
  return (peak < N_FFT / 2 ? peak : peak - N_FFT) * binHz;
}

let PLUTO = process.env.GNOSIS_PLUTO_URI || '';

async function main() {
  if (!PLUTO) { const r = await sh(IIO_INFO, ['-s']); const m = (r.out + r.err).match(/usb:[0-9.]+/); PLUTO = m ? m[0] : ''; }
  if (!PLUTO) { console.error('no Pluto'); process.exit(1); }
  console.log(`=== two-witness plurality test (Pluto ${PLUTO} TX + 2 RTL RX), tone @ ${F0} Hz ===`);
  await sh(IIO_ATTR, ['-u', PLUTO, '-c', 'ad9361-phy', 'altvoltage1', 'frequency', String(LO)]);
  await sh(IIO_ATTR, ['-u', PLUTO, '-c', 'ad9361-phy', 'voltage0', 'sampling_frequency', String(FS)]);
  await sh(IIO_ATTR, ['-u', PLUTO, '-c', 'ad9361-phy', 'voltage0', 'rf_bandwidth', String(FS)]);
  for (let i = 0; i < 3; i++) await sh(IIO_ATTR, ['-u', PLUTO, '-c', 'ad9361-phy', 'voltage0', 'hardwaregain', '-10']);

  const iq = `${ART}/tone.iq16`; writeFileSync(iq, synthTone(F0));
  const fd = openSync(iq, 'r');
  const tx = spawn(IIO_WRITEDEV, ['-u', PLUTO, '-b', String(N_TX), '-c', 'cf-ad9361-dds-core-lpc', 'voltage0', 'voltage1'], { env, stdio: [fd, 'ignore', 'ignore'] });
  await new Promise((r) => setTimeout(() => r(), 400));
  // capture on BOTH RTLs concurrently — two independent witnesses, same instant
  const cap0 = `${ART}/w0.u8`, cap1 = `${ART}/w1.u8`;
  await Promise.all([
    sh(RTL, ['-d', '0', '-f', String(LO), '-s', String(FS), '-g', '30', '-n', String(N_CAP), cap0]),
    sh(RTL, ['-d', '1', '-f', String(LO), '-s', String(FS), '-g', '30', '-n', String(N_CAP), cap1]),
  ]);
  tx.kill('SIGKILL');

  const m0 = measureCarrier(readFileSync(cap0));
  const m1 = measureCarrier(readFileSync(cap1));
  const d0 = m0 - F0, d1 = m1 - F0, d01 = m0 - m1;
  console.log(`\nwitness RTL#0 (SN 94092559): carrier ${m0.toFixed(1)} Hz   beat vs Pluto = ${d0.toFixed(1)} Hz`);
  console.log(`witness RTL#1 (SN 78922015): carrier ${m1.toFixed(1)} Hz   beat vs Pluto = ${d1.toFixed(1)} Hz`);
  console.log(`\nthree pairwise beats (the proof of plurality):`);
  console.log(`  Pluto  ⇔ RTL#0 :  ${Math.abs(d0).toFixed(1)} Hz  ${Math.abs(d0) > 1 ? 'TWO BEINGS' : 'one (shared clock)'}`);
  console.log(`  Pluto  ⇔ RTL#1 :  ${Math.abs(d1).toFixed(1)} Hz  ${Math.abs(d1) > 1 ? 'TWO BEINGS' : 'one (shared clock)'}`);
  console.log(`  RTL#0  ⇔ RTL#1 :  ${Math.abs(d01).toFixed(1)} Hz  ${Math.abs(d01) > 1 ? 'TWO BEINGS' : 'one (shared clock)'}`);
  const three = Math.abs(d0) > 1 && Math.abs(d1) > 1 && Math.abs(d01) > 1;
  console.log(`\n${three ? 'PLURALITY IN TRIPLICATE ✓ — three oscillators, three irreducible beats, three distinct beings, witnessed externally by two eyes that share no clock.' : 'a pair shares a clock — fewer than three beings on the bench.'}`);
}

main();
